# routing_facade.py
# Stateless routing facade for strangler-pattern AI migration.
# Routing decisions are driven by feature flags; no hard-coded percentages.

from dataclasses import dataclass
from enum import Enum
from typing import Callable
import threading
import copy

class Disposition(Enum):
    LEGACY = "legacy"
    SHADOW = "shadow"   # legacy is live path, new agent runs in background
    NEW = "new"

@dataclass
class Request:
    request_id: str
    request_type: str
    payload: dict
    user_cohort: str

@dataclass
class Response:
    content: str
    source: str   # "legacy" or "new_agent"
    latency_ms: float

class AIRoutingFacade:
    def __init__(
        self,
        legacy_handler: Callable[[Request], Response],
        new_agent_handler: Callable[[Request], Response],
        routing_fn: Callable[[Request], Disposition],
        shadow_observer: Callable[[Request, Response, Response], None] | None = None,
    ):
        self._legacy = legacy_handler
        self._new_agent = new_agent_handler
        self._routing_fn = routing_fn
        self._shadow_observer = shadow_observer

    def handle(self, request: Request) -> Response:
        disposition = self._routing_fn(request)

        if disposition == Disposition.LEGACY:
            return self._legacy(request)

        if disposition == Disposition.NEW:
            return self._new_agent(request)

        # SHADOW: legacy is the live path; new agent runs in background
        if disposition == Disposition.SHADOW:
            live_response = self._legacy(request)
            if self._shadow_observer:
                shadow_req = copy.deepcopy(request)
                t = threading.Thread(
                    target=self._run_shadow,
                    args=(shadow_req, live_response),
                    daemon=True,
                )
                t.start()
            return live_response

        raise ValueError(f"Unknown disposition: {disposition}")

    def _run_shadow(self, request: Request, live_response: Response) -> None:
        try:
            shadow_response = self._new_agent(request)
            if self._shadow_observer:
                self._shadow_observer(request, live_response, shadow_response)
        except Exception as exc:
            # Shadow failures must never surface to users
            print(f"Shadow mode error for {request.request_id}: {exc}")
